     1→"use client";
     2→
     3→import { useState } from "react";
     4→import useSWR, { mutate } from "swr";
     5→import Link from "next/link";
     6→import {
     7→  projects as projectsApi,
     8→  releases as releasesApi,
     9→  sources as sourcesApi,
    10→  semanticReleases as srApi,
    11→} from "@/lib/api/client";
    12→import { getProviderIcon } from "@/components/ui/provider-badge";
    13→import { timeAgo, validateRepository, formatInterval } from "@/lib/format";
    14→import { Plus, X, ArrowRight } from "lucide-react";
    15→import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
    16→import { ProjectForm } from "@/components/projects/project-form";
    17→import type { Project, Source } from "@/lib/api/types";
    18→
    19→/* ---------- Inline Add Source Form ---------- */
    20→
    21→function InlineSourceForm({
    22→  projectId,
    23→  onDone,
    24→}: {
    25→  projectId: string;
    26→  onDone: () => void;
    27→}) {
    28→  const [provider, setProvider] = useState("github");
    29→  const [repository, setRepository] = useState("");
    30→  const [pollInterval, setPollInterval] = useState("86400");
    31→  const [saving, setSaving] = useState(false);
    32→  const [error, setError] = useState("");
    33→
    34→  const handleAdd = async (e: React.FormEvent) => {
    35→    e.preventDefault();
    36→    if (!repository.trim()) return;
    37→    setSaving(true);
    38→    setError("");
    39→    try {
    40→      const repoError = validateRepository(provider, repository.trim());
    41→      if (repoError) {
    42→        setError(repoError);
    43→        setSaving(false);
    44→        return;
    45→      }
    46→      const res = await sourcesApi.create(projectId, {
    47→        provider,
    48→        repository: repository.trim(),
    49→        poll_interval_seconds: Number(pollInterval) || 86400,
    50→        enabled: true,
    51→      });
    52→      if (res.data?.id) sourcesApi.poll(res.data.id).catch(() => {});
    53→      mutate(`project-${projectId}-card-sources`);
    54→      onDone();
    55→    } catch (err: unknown) {
    56→      setError(err instanceof Error ? err.message : "Failed to add source");
    57→    } finally {
    58→      setSaving(false);
    59→    }
    60→  };
    61→
    62→  return (
    63→    <form onSubmit={handleAdd} className="mt-2 rounded-md border p-3 space-y-2" style={{ borderColor: "#e8e8e5", backgroundColor: "#fafaf9" }}>
    64→      {error && <div className="text-[12px] text-red-600">{error}</div>}
    65→      <div className="flex items-center gap-2">
    66→        <select
    67→          value={provider}
    68→          onChange={(e) => setProvider(e.target.value)}
    69→          className="rounded-md border px-2 py-1 text-[12px]"
    70→          style={{ borderColor: "#e8e8e5", fontFamily: "var(--font-dm-sans)" }}
    71→        >
    72→          <option value="github">GitHub</option>
    73→          <option value="dockerhub">Docker Hub</option>
    74→        </select>
    75→        <input
    76→          type="text"
    77→          value={repository}
    78→          onChange={(e) => setRepository(e.target.value)}
    79→          placeholder="e.g. ethereum/go-ethereum"
    80→          className="flex-1 rounded-md border px-2 py-1 text-[12px]"
    81→          style={{ borderColor: "#e8e8e5", fontFamily: "'JetBrains Mono', monospace" }}
    82→        />
    83→        <input
    84→          type="number"
    85→          min={60}
    86→          value={pollInterval}
    87→          onChange={(e) => setPollInterval(e.target.value)}
    88→          className="w-20 rounded-md border px-2 py-1 text-[12px]"
    89→          style={{ borderColor: "#e8e8e5" }}
    90→          title="Poll interval (seconds)"
    91→        />
    92→      </div>
    93→      <div className="flex items-center justify-end gap-2">
    94→        <button
    95→          type="button"
    96→          onClick={onDone}
    97→          className="text-[12px] text-[#9ca3af] hover:text-[#6b7280]"
    98→        >
    99→          Cancel
   100→        </button>
   101→        <button
   102→          type="submit"
   103→          disabled={saving || !repository.trim()}
   104→          className="rounded-md px-3 py-1 text-[12px] font-medium text-white disabled:opacity-40"
   105→          style={{ backgroundColor: "#e8601a" }}
   106→        >
   107→          {saving ? "Adding..." : "Add"}
   108→        </button>
   109→      </div>
   110→    </form>
   111→  );
   112→}
   113→
   114→/* ---------- Sources Section ---------- */
   115→
   116→function SourcesSection({ projectId }: { projectId: string }) {
   117→  const [adding, setAdding] = useState(false);
   118→  const { data } = useSWR(`project-${projectId}-card-sources`, () =>
   119→    sourcesApi.listByProject(projectId)
   120→  );
   121→  const sources = data?.data ?? [];
   122→
   123→  return (
   124→    <div className="px-4 py-3 md:border-r" style={{ borderColor: "#e8e8e5" }}>
   125→      <div className="flex items-center justify-between mb-1">
   126→        <span
   127→          className="text-[11px] font-medium uppercase tracking-[0.08em]"
   128→          style={{ color: "#9ca3af", fontFamily: "var(--font-dm-sans)" }}
   129→        >
   130→          Sources
   131→        </span>
   132→        {!adding && (
   133→          <button
   134→            onClick={() => setAdding(true)}
   135→            className="inline-flex items-center gap-1 text-[11px] font-medium transition-colors hover:opacity-80"
   136→            style={{ color: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
   137→          >
   138→            <Plus className="h-3 w-3" />
   139→            Add Source
   140→          </button>
   141→        )}
   142→        {adding && (
   143→          <button
   144→            onClick={() => setAdding(false)}
   145→            className="text-[#9ca3af] hover:text-[#6b7280]"
   146→          >
   147→            <X className="h-3.5 w-3.5" />
   148→          </button>
   149→        )}
   150→      </div>
   151→
   152→      {sources.length > 0 ? (
   153→        <div className="space-y-1">
   154→          {sources.map((source) => {
   155→            const Icon = getProviderIcon(source.provider);
   156→            return (
   157→              <div
   158→                key={source.id}
   159→                className="flex items-center gap-2 text-[12px]"
   160→                style={{ fontFamily: "var(--font-dm-sans)" }}
   161→              >
   162→                {Icon && <Icon size={13} className="shrink-0" style={{ color: "#6b7280" }} />}
   163→                <span style={{ fontFamily: "'JetBrains Mono', monospace", color: "#374151" }}>
   164→                  {source.repository}
   165→                </span>
   166→                <span
   167→                  className="ml-auto flex items-center gap-1.5 text-[11px]"
   168→                  style={{ color: "#9ca3af" }}
   169→                >
   170→                  <span
   171→                    className="inline-block h-1.5 w-1.5 rounded-full"
   172→                    style={{ backgroundColor: source.enabled ? "#16a34a" : "#d1d5db" }}
   173→                  />
   174→                  {source.enabled ? "Active" : "Disabled"}
   175→                  <span className="ml-1" style={{ color: "#c4c4c0" }}>
   176→                    {formatInterval(source.poll_interval_seconds)}
   177→                  </span>
   178→                </span>
   179→              </div>
   180→            );
   181→          })}
   182→        </div>
   183→      ) : (
   184→        <p className="text-[12px] italic" style={{ color: "#c4c4c0" }}>
   185→          No sources configured
   186→        </p>
   187→      )}
   188→
   189→      {adding && (
   190→        <InlineSourceForm projectId={projectId} onDone={() => setAdding(false)} />
   191→      )}
   192→    </div>
   193→  );
   194→}
   195→
   196→/* ---------- Recent Releases Section ---------- */
   197→
   198→function RecentReleasesSection({ projectId }: { projectId: string }) {
   199→  const { data: relData } = useSWR(`project-${projectId}-card-releases`, () =>
   200→    releasesApi.listByProject(projectId, 1, 5)
   201→  );
   202→  const { data: srcData } = useSWR(`project-${projectId}-card-sources`, () =>
   203→    sourcesApi.listByProject(projectId)
   204→  );
   205→  const releases = relData?.data ?? [];
   206→  const sources = srcData?.data ?? [];
   207→
   208→  const sourceMap = new Map<string, Source>();
   209→  for (const s of sources) sourceMap.set(s.id, s);
   210→
   211→  return (
   212→    <div className="border-t md:border-t-0 md:border-r px-4 py-3" style={{ borderColor: "#e8e8e5" }}>
   213→      <span
   214→        className="text-[11px] font-medium uppercase tracking-[0.08em] mb-1 block"
   215→        style={{ color: "#9ca3af", fontFamily: "var(--font-dm-sans)" }}
   216→      >
   217→        Recent Releases
   218→      </span>
   219→
   220→      {releases.length > 0 ? (
   221→        <div className="space-y-1">
   222→          {releases.map((r) => {
   223→            const src = sourceMap.get(r.source_id);
   224→            const Icon = src ? getProviderIcon(src.provider) : undefined;
   225→            return (
   226→              <Link
   227→                key={r.id}
   228→                href={`/releases/${r.id}`}
   229→                className="flex items-center gap-2 text-[12px] transition-colors hover:bg-[#fafaf9] rounded px-1 -mx-1 py-0.5"
   230→              >
   231→                <span
   232→                  className="inline-flex items-center rounded px-1.5 py-0.5 text-[12px] leading-none"
   233→                  style={{
   234→                    backgroundColor: "#f3f3f1",
   235→                    fontFamily: "'JetBrains Mono', monospace",
   236→                    color: "#374151",
   237→                  }}
   238→                >
   239→                  {r.version}
   240→                </span>
   241→                {Icon && <Icon size={11} className="shrink-0" style={{ color: "#9ca3af" }} />}
   242→                {src && (
   243→                  <span className="text-[11px] truncate" style={{ color: "#9ca3af" }}>
   244→                    {src.repository}
   245→                  </span>
   246→                )}
   247→                <span className="ml-auto text-[11px] shrink-0" style={{ color: "#c4c4c0" }}>
   248→                  {timeAgo(r.released_at || r.created_at)}
   249→                </span>
   250→              </Link>
   251→            );
   252→          })}
   253→          <Link
   254→            href={`/releases?project=${projectId}`}
   255→            className="block text-[11px] mt-1 hover:underline"
   256→            style={{ color: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
   257→          >
   258→            View all &rarr;
   259→          </Link>
   260→        </div>
   261→      ) : (
   262→        <p className="text-[12px] italic" style={{ color: "#c4c4c0" }}>
   263→          No releases yet
   264→        </p>
   265→      )}
   266→    </div>
   267→  );
   268→}
   269→
   270→/* ---------- Semantic Releases Section ---------- */
   271→
   272→const URGENCY_COLORS: Record<string, { bg: string; text: string }> = {
   273→  critical: { bg: "#dc2626", text: "#ffffff" },
   274→  high: { bg: "#f97316", text: "#ffffff" },
   275→};
   276→
   277→function SemanticReleasesSection({ projectId }: { projectId: string }) {
   278→  const { data } = useSWR(`project-${projectId}-card-sr`, () =>
   279→    srApi.list(projectId, 1, 3)
   280→  );
   281→  const items = data?.data ?? [];
   282→
   283→  return (
   284→    <div className="border-t md:border-t-0 px-4 py-3" style={{ borderColor: "#e8e8e5" }}>
   285→      <span
   286→        className="text-[11px] font-medium uppercase tracking-[0.08em] mb-1 block"
   287→        style={{ color: "#9ca3af", fontFamily: "var(--font-dm-sans)" }}
   288→      >
   289→        Semantic Releases
   290→      </span>
   291→
   292→      {items.length > 0 ? (
   293→        <div className="space-y-1">
   294→          {items.map((sr) => {
   295→            const urgencyStyle = sr.report?.urgency
   296→              ? URGENCY_COLORS[sr.report.urgency.toLowerCase()]
   297→              : undefined;
   298→            return (
   299→              <Link
   300→                key={sr.id}
   301→                href={`/projects/${projectId}/semantic-releases/${sr.id}`}
   302→                className="flex items-center gap-2 text-[12px] transition-colors hover:bg-[#fafaf9] rounded px-1 -mx-1 py-0.5"
   303→              >
   304→                <span
   305→                  className="inline-flex items-center rounded px-1.5 py-0.5 text-[12px] leading-none"
   306→                  style={{
   307→                    backgroundColor: "#eff6ff",
   308→                    fontFamily: "'JetBrains Mono', monospace",
   309→                    color: "#1d4ed8",
   310→                  }}
   311→                >
   312→                  {sr.version}
   313→                </span>
   314→                <span
   315→                  className="text-[11px]"
   316→                  style={{ color: "#9ca3af" }}
   317→                >
   318→                  {sr.status}
   319→                </span>
   320→                {urgencyStyle && (
   321→                  <span
   322→                    className="inline-flex items-center rounded-full px-1.5 py-0.5 text-[10px] font-medium leading-none"
   323→                    style={{ backgroundColor: urgencyStyle.bg, color: urgencyStyle.text }}
   324→                  >
   325→                    {sr.report!.urgency}
   326→                  </span>
   327→                )}
   328→                {sr.report?.summary && (
   329→                  <span
   330→                    className="text-[11px] truncate flex-1"
   331→                    style={{ color: "#c4c4c0" }}
   332→                  >
   333→                    {sr.report.summary.length > 60
   334→                      ? sr.report.summary.slice(0, 60) + "\u2026"
   335→                      : sr.report.summary}
   336→                  </span>
   337→                )}
   338→                <span className="ml-auto text-[11px] shrink-0" style={{ color: "#c4c4c0" }}>
   339→                  {timeAgo(sr.completed_at || sr.created_at)}
   340→                </span>
   341→              </Link>
   342→            );
   343→          })}
   344→          <Link
   345→            href={`/semantic-releases?project=${projectId}`}
   346→            className="block text-[11px] mt-1 hover:underline"
   347→            style={{ color: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
   348→          >
   349→            View all &rarr;
   350→          </Link>
   351→        </div>
   352→      ) : (
   353→        <p className="text-[12px] italic" style={{ color: "#c4c4c0" }}>
   354→          No semantic releases yet
   355→        </p>
   356→      )}
   357→    </div>
   358→  );
   359→}
   360→
   361→/* ---------- Project Card ---------- */
   362→
   363→function ProjectCard({ project }: { project: Project }) {
   364→  return (
   365→    <div
   366→      className="overflow-hidden rounded-md"
   367→      style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
   368→    >
   369→      {/* Header */}
   370→      <div className="px-4 py-3">
   371→        <div className="min-w-0">
   372→          <Link
   373→            href={`/projects/${project.id}`}
   374→            className="group inline-flex items-center gap-1.5 text-[16px] font-bold transition-colors"
   375→            style={{ fontFamily: "var(--font-fraunces)", color: "#e8601a" }}
   376→          >
   377→            {project.name}
   378→            <ArrowRight className="h-3.5 w-3.5 opacity-0 -translate-x-1 transition-all group-hover:opacity-100 group-hover:translate-x-0" />
   379→          </Link>
   380→          {project.description && (
   381→            <p
   382→              className="mt-0.5 text-[13px] truncate"
   383→              style={{ color: "#6b7280", fontFamily: "var(--font-dm-sans)" }}
   384→            >
   385→              {project.description}
   386→            </p>
   387→          )}
   388→        </div>
   389→      </div>
   390→
   391→      {/* Content columns: sources | recent releases | semantic releases */}
   392→      <div className="grid grid-cols-1 md:grid-cols-3 border-t" style={{ borderColor: "#e8e8e5" }}>
   393→        <SourcesSection projectId={project.id} />
   394→        <RecentReleasesSection projectId={project.id} />
   395→        <SemanticReleasesSection projectId={project.id} />
   396→      </div>
   397→    </div>
   398→  );
   399→}
   400→
   401→/* ---------- Page ---------- */
   402→
   403→export default function ProjectsPage() {
   404→  const [createOpen, setCreateOpen] = useState(false);
   405→  const { data, isLoading } = useSWR("projects", () => projectsApi.list());
   406→  const items = data?.data ?? [];
   407→
   408→  return (
   409→    <div className="flex flex-col gap-4 fade-in">
   410→      <div className="flex items-center justify-between">
   411→        <div>
   412→          <h1
   413→            style={{
   414→              fontFamily: "var(--font-fraunces)",
   415→              fontSize: "24px",
   416→              fontWeight: 700,
   417→              color: "#111113",
   418→            }}
   419→          >
   420→            Projects
   421→          </h1>
   422→          <p
   423→            className="mt-1 text-[13px] text-[#6b7280]"
   424→            style={{ fontFamily: "var(--font-dm-sans)" }}
   425→          >
   426→            Tracked software projects and their recent releases.
   427→          </p>
   428→        </div>
   429→        <button
   430→          onClick={() => setCreateOpen(true)}
   431→          className="flex items-center gap-1.5 rounded px-3 py-1.5 text-[13px] text-white transition-opacity hover:opacity-90"
   432→          style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
   433→        >
   434→          <Plus className="h-3.5 w-3.5" />
   435→          New Project
   436→        </button>
   437→      </div>
   438→
   439→      {isLoading ? (
   440→        <p
   441→          className="px-4 py-8 text-center text-[14px] italic text-[#9ca3af]"
   442→          style={{ fontFamily: "var(--font-fraunces)" }}
   443→        >
   444→          Loading...
   445→        </p>
   446→      ) : items.length === 0 ? (
   447→        <div
   448→          className="flex flex-col items-center justify-center rounded-md border py-12"
   449→          style={{ borderColor: "#e8e8e5", backgroundColor: "#ffffff" }}
   450→        >
   451→          <p
   452→            className="text-[14px] italic text-[#9ca3af]"
   453→            style={{ fontFamily: "var(--font-fraunces)" }}
   454→          >
   455→            No projects yet — create one to start tracking releases
   456→          </p>
   457→          <button
   458→            onClick={() => setCreateOpen(true)}
   459→            className="mt-4 flex items-center gap-1.5 rounded px-3 py-1.5 text-[13px] text-white transition-opacity hover:opacity-90"
   460→            style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
   461→          >
   462→            <Plus className="h-3.5 w-3.5" />
   463→            New Project
   464→          </button>
   465→        </div>
   466→      ) : (
   467→        <div className="space-y-4">
   468→          {items.map((project) => (
   469→            <ProjectCard key={project.id} project={project} />
   470→          ))}
   471→        </div>
   472→      )}
   473→
   474→      <Dialog open={createOpen} onOpenChange={setCreateOpen}>
   475→        <DialogContent className="sm:max-w-lg">
   476→          <DialogHeader>
   477→            <DialogTitle>Create Project</DialogTitle>
   478→          </DialogHeader>
   479→          <ProjectForm
   480→            title="Create Project"
   481→            onSubmit={async (result) => {
   482→              const created = await projectsApi.create(result.project);
   483→              if (result.source && created.data?.id) {
   484→                const res = await sourcesApi.create(created.data.id, result.source);
   485→                if (res.data?.id) sourcesApi.poll(res.data.id).catch(() => {});
   486→              }
   487→            }}
   488→            onSuccess={() => { setCreateOpen(false); mutate("projects"); }}
   489→            onCancel={() => setCreateOpen(false)}
   490→          />
   491→        </DialogContent>
   492→      </Dialog>
   493→    </div>
   494→  );
   495→}
