    52→
    53→  const handleSubmit = async (e: React.FormEvent) => {
    54→    e.preventDefault();
    55→    setError("");
    56→    setSaving(true);
    57→    try {
    58→      const result: ProjectFormResult = {
    59→        project: {
    60→          name,
    61→          description: description || undefined,
    62→        },
    63→      };
    64→      if (showSource && repository.trim()) {
    65→        const repoError = validateRepository(provider, repository.trim());
