   123→                  className="text-[#9ca3af] hover:text-[#6b7280]"
   124→                >
   125→                  <X className="h-4 w-4" />
   126→                </button>
   127→              </div>
   128→              <div className="space-y-2">
   129→                <Label>Provider</Label>
   130→                <Select value={provider} onValueChange={setProvider}>
   131→                  <SelectTrigger><SelectValue /></SelectTrigger>
   132→                  <SelectContent>
   133→                    <SelectItem value="github">GitHub</SelectItem>
   134→                    <SelectItem value="dockerhub">Docker Hub</SelectItem>
   135→                  </SelectContent>
   136→                </Select>
   137→              </div>
   138→              <div className="space-y-2">
   139→                <Label htmlFor="repository">Repository</Label>
   140→                <Input
   141→                  id="repository"
   142→                  value={repository}
   143→                  onChange={(e) => setRepository(e.target.value)}
   144→                  placeholder="e.g. ethereum/go-ethereum"
   145→                />
   146→              </div>
   147→              <div className="space-y-2">
   148→                <Label htmlFor="poll_interval">Poll Interval (seconds)</Label>
   149→                <Input
   150→                  id="poll_interval"
