   824→        </DialogContent>
   825→      </Dialog>
   826→
   827→      {/* Source delete dialog */}
   828→      <ConfirmDialog
   829→        open={!!deletingSourceId}
   830→        onOpenChange={(open) => { if (!open) setDeletingSourceId(null); }}
   831→        title="Delete Source"
   832→        description="This will permanently delete this source and its releases."
   833→        onConfirm={async () => { if (deletingSourceId) { await sourcesApi.delete(deletingSourceId); mutateSources(); } }}
